import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface PriorityMessage {
  sender: string;
  subject: string;
  timestamp: string;
}

interface DailyVolume {
  day: string;
  emails: number;
}

interface EmailData {
  unreadCount: number;
  priorityMessages: PriorityMessage[];
  dailyVolumeTrend: DailyVolume[];
}

export default function Widget() {
  const emailData = response.data as EmailData;
  const { unreadCount, priorityMessages, dailyVolumeTrend } = emailData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1E1E1E' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              Mail Manager
            </Typography>
            <Typography variant="h4" sx={{ color: '#FF5722', fontWeight: 700 }}>
              {unreadCount} Unread
            </Typography>
          </Box>

          <Stack spacing={1}>
            {priorityMessages.map((message, index) => (
              <Box key={index} sx={{ bgcolor: '#333', p: 1, borderRadius: 1 }}>
                <Typography variant="body2" sx={{ color: '#FFC107', fontWeight: 600 }}>
                  {message.sender}
                </Typography>
                <Typography variant="body2" sx={{ color: '#FFF' }}>
                  {message.subject}
                </Typography>
                <Typography variant="caption" sx={{ color: '#BBB' }}>
                  {message.timestamp}
                </Typography>
              </Box>
            ))}
          </Stack>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'bar',
                  data: dailyVolumeTrend.map((d) => d.emails),
                  color: '#FF5722',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: dailyVolumeTrend.map((d) => d.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'emails' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <BarPlot />
              </g>
              <ChartsXAxis axisId="days" tickLabelStyle={{ fontSize: 10, fill: '#FFF' }} />
              <ChartsYAxis axisId="emails" tickLabelStyle={{ fontSize: 10, fill: '#FFF' }} />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
